external_knowledge:
- 'Seasoned gamers' refers to players who have played at least 5 games; 
- 'Broadened their horizons' means having experience in 'Game Mode 1'; 
- 'Average performance scores' is the average of the scores obtained by a player in the specified game mode.

sql:
SELECT MAX(score) AS highest_score
FROM leaderboard_entries
WHERE leaderboard_id = 1;

SELECT squad_name
FROM squads
WHERE leader_id = 1;

SELECT COUNT(*) AS update_count
FROM game_updates
WHERE game_id = 1;

SELECT COUNT(player_id) AS total_players
FROM player_teams
WHERE team_id = 0;

SELECT game_name
FROM games
WHERE game_id IN (
  SELECT DISTINCT game_id
  FROM game_updates
);

SELECT COUNT(player_id) AS total_players
FROM player_squads
WHERE squad_id = 0;

SELECT player_name
FROM players
WHERE player_id IN (
  SELECT DISTINCT player_id
  FROM game_results
);

SELECT AVG(gr.score) AS average_score
FROM game_results gr
WHERE gr.game_id = 1 AND gr.game_mode_id = 1;

SELECT game_mode_name 
FROM game_modes 
WHERE max_players > 10;

SELECT COUNT(player_id) AS player_count
FROM player_boons
WHERE boon_name = 'regeneration' AND game_mode_id = 1 AND game_id = 1;
